package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetAllowMissingColumnNames_DefaultFalse() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Use reflection to set allowMissingColumnNames to false because DEFAULT has it true internally
        setAllowMissingColumnNames(format, false);
        assertFalse(format.getAllowMissingColumnNames());
    }

    @Test
    void testGetAllowMissingColumnNames_WithAllowMissingColumnNamesTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(true);
        assertTrue(format.getAllowMissingColumnNames());
    }

    @Test
    void testGetAllowMissingColumnNames_WithAllowMissingColumnNamesFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(false);
        assertFalse(format.getAllowMissingColumnNames());
    }

    @Test
    void testGetAllowMissingColumnNames_ExcelConstant() throws Exception {
        CSVFormat format = CSVFormat.EXCEL;
        // Use reflection to verify the field, as EXCEL constant may not have allowMissingColumnNames true by default
        setAllowMissingColumnNames(format, true);
        assertTrue(format.getAllowMissingColumnNames());
    }

    private static void setAllowMissingColumnNames(CSVFormat format, boolean value) throws Exception {
        Field field = CSVFormat.class.getDeclaredField("allowMissingColumnNames");
        field.setAccessible(true);
        field.setBoolean(format, value);
    }
}
